ALTER TABLE provider_connections ADD COLUMN config_encrypted INTEGER NOT NULL DEFAULT 0;
ALTER TABLE refunds ADD COLUMN provider_dispatch_json TEXT NOT NULL DEFAULT '{}';
ALTER TABLE payment_disputes ADD COLUMN provider_submission_json TEXT NOT NULL DEFAULT '{}';
ALTER TABLE dispute_evidence ADD COLUMN provider_submission_json TEXT NOT NULL DEFAULT '{}';
CREATE TABLE IF NOT EXISTS app_billing_plans (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, app_id TEXT NOT NULL, code TEXT NOT NULL, name TEXT NOT NULL, billing_type TEXT NOT NULL DEFAULT 'recurring', amount_cents INTEGER NOT NULL DEFAULT 0, usage_unit TEXT NOT NULL DEFAULT 'event', usage_cents INTEGER NOT NULL DEFAULT 0, interval_unit TEXT NOT NULL DEFAULT 'month', trial_days INTEGER NOT NULL DEFAULT 0, active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (app_id) REFERENCES commerce_apps(id) ON DELETE CASCADE, UNIQUE (merchant_id, app_id, code));
CREATE TABLE IF NOT EXISTS app_billing_subscriptions (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, installation_id TEXT NOT NULL, plan_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'active', current_period_start TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, current_period_end TEXT NOT NULL DEFAULT '', external_provider TEXT NOT NULL DEFAULT 'internal', external_ref TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (installation_id) REFERENCES app_installations(id) ON DELETE CASCADE, FOREIGN KEY (plan_id) REFERENCES app_billing_plans(id) ON DELETE CASCADE, UNIQUE (merchant_id, installation_id));
CREATE TABLE IF NOT EXISTS app_usage_events (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, subscription_id TEXT NOT NULL, metric_key TEXT NOT NULL DEFAULT 'event', quantity INTEGER NOT NULL DEFAULT 1, unit_cents INTEGER NOT NULL DEFAULT 0, total_cents INTEGER NOT NULL DEFAULT 0, idempotency_key TEXT NOT NULL DEFAULT '', meta_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (subscription_id) REFERENCES app_billing_subscriptions(id) ON DELETE CASCADE, UNIQUE (merchant_id, idempotency_key));
CREATE TABLE IF NOT EXISTS app_billing_invoices (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, subscription_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'open', currency TEXT NOT NULL DEFAULT 'USD', base_cents INTEGER NOT NULL DEFAULT 0, usage_cents INTEGER NOT NULL DEFAULT 0, total_cents INTEGER NOT NULL DEFAULT 0, line_items_json TEXT NOT NULL DEFAULT '[]', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, paid_at TEXT, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (subscription_id) REFERENCES app_billing_subscriptions(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS domain_certificate_jobs (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, domain_id TEXT NOT NULL, provider TEXT NOT NULL DEFAULT 'cloudflare', external_hostname_id TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'pending', validation_records_json TEXT NOT NULL DEFAULT '[]', result_json TEXT NOT NULL DEFAULT '{}', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (domain_id) REFERENCES custom_domains(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS idx_app_billing_plans_merchant ON app_billing_plans (merchant_id, app_id, active);
CREATE INDEX IF NOT EXISTS idx_app_billing_subscriptions_merchant ON app_billing_subscriptions (merchant_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_app_usage_events_subscription ON app_usage_events (merchant_id, subscription_id, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_app_billing_invoices_merchant ON app_billing_invoices (merchant_id, status, created_at DESC);
CREATE INDEX IF NOT EXISTS idx_domain_certificate_jobs_merchant ON domain_certificate_jobs (merchant_id, domain_id, created_at DESC);
